syntax.postgresql:
-- First, create a foreign data wrapper and server
CREATE EXTENSION postgres_fdw;

CREATE SERVER remote_server
  FOREIGN DATA WRAPPER postgres_fdw
  OPTIONS (host 'remote-host', dbname 'remote_db');

CREATE FOREIGN TABLE remote_users (
  id INT,
  username VARCHAR(50),
  email VARCHAR(100)
) SERVER remote_server
  OPTIONS (table_name 'users');

syntax.mysql:
CREATE SERVER remote_server
  FOREIGN DATA WRAPPER mysql
  OPTIONS (HOST 'remote-host', DATABASE 'remote_db', USER 'admin', PASSWORD 'secret');

CREATE TABLE remote_users (
  id INT,
  username VARCHAR(50),
  email VARCHAR(100)
) ENGINE=FEDERATED
  CONNECTION='remote_server/users';

syntax.mariadb:
