syntax.postgresql:
CREATE TABLE products (
  id SERIAL PRIMARY KEY,
  name VARCHAR(100) NOT NULL,
  attributes JSONB NOT NULL DEFAULT '{}'
);

-- Query JSON data
SELECT name, attributes->>'color' AS color
FROM products
WHERE attributes @> '{"category": "electronics"}';

syntax.mysql:
CREATE TABLE products (
  id INT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(100) NOT NULL,
  attributes JSON NOT NULL
);

-- Query JSON data
SELECT name, JSON_EXTRACT(attributes, '$.color') AS color
FROM products
WHERE JSON_CONTAINS(attributes, '"electronics"', '$.category');

syntax.mariadb:
CREATE TABLE products (
  id INT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(100) NOT NULL,
  attributes JSON NOT NULL
);

-- Query JSON data
SELECT name, JSON_VALUE(attributes, '$.color') AS color
FROM products
WHERE JSON_CONTAINS(attributes, '"electronics"', '$.category');

syntax.sqlite:
CREATE TABLE products (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  attributes TEXT NOT NULL DEFAULT '{}'
);

-- Query JSON data (requires JSON1 extension)
SELECT name, json_extract(attributes, '$.color') AS color
FROM products
WHERE json_extract(attributes, '$.category') = 'electronics';
